24	  beforeEach(() => {
25	    mockFetch.mockReset();
26	  });
27	
28	  it("listMarkets calls /v1/markets", async () => {
29	    const body = { markets: [], count: 0, meta: { apiVersion: "1.0", timestamp: "" } };
30	    mockFetch.mockResolvedValue(jsonResponse(body));
31	    const result = await listMarkets();
32	    expect(mockFetch).toHaveBeenCalledWith("/v1/markets", expect.objectContaining({ headers: {} }));
33	    expect(result.count).toBe(0);
34	  });
35	
36	  it("listMarkets passes status filter", async () => {
37	    const body = { markets: [], count: 0, meta: { apiVersion: "1.0", timestamp: "" } };
38	    mockFetch.mockResolvedValue(jsonResponse(body));
39	    await listMarkets({ status: "active" });
40	    expect(mockFetch).toHaveBeenCalledWith("/v1/markets?status=active", expect.any(Object));
41	  });
42	
43	  it("listMarkets passes normalized sort and search filters", async () => {
44	    const body = { markets: [], count: 0, meta: { apiVersion: "1.0", timestamp: "" } };
45	    mockFetch.mockResolvedValue(jsonResponse(body));
46	    await listMarkets({ status: "all", sort: "volume", q: "  ETH  " });
47	    expect(mockFetch).toHaveBeenCalledWith("/v1/markets?sort=volume&q=ETH", expect.any(Object));
